1	//! Stream-aware output framing around opaque theory payloads.
2	//!
3	//! A batch run writes to two independent streams (see `workspace/BEHAVIOR.md`
4	//! §10). This module models which text lands on which stream and assembles both
5	//! byte-exactly. The theory pretty-print (`theory <name> … end`, including any
6	//! `WARNING:` block and the `Generated from:` comment) is an opaque payload slot;
7	//! everything around it — the maude preamble, the per-theory progress markers, and
8	//! the "summary of summaries" block — is built here.
9	//!
10	//! Stream assignment: the maude preamble and progress markers go to stderr;
11	//! payloads and the summary block go to stdout.
12	
13	use crate::stream::Streams;
14	use crate::version::{maude_preamble, MaudeInfo};
15	
16	/// Width of the `=` rule that brackets the summary block (observed: 78).
17	const RULE_WIDTH: usize = 78;
18	
19	/// Per-theory progress phases, in the order printed for a fully closed theory.
20	#[derive(Debug, Clone, Copy)]
21	pub enum Phase {
22	    Loaded,
23	    Translated,
24	    DerivationChecksStarted,
25	    DerivationChecksEnded,
26	    Closed,
27	}
28	
29	impl Phase {
30	    fn text(self) -> &'static str {
31	        match self {
32	            Phase::Loaded => "Theory loaded",
33	            Phase::Translated => "Theory translated",
34	            Phase::DerivationChecksStarted => "Derivation checks started",
35	            Phase::DerivationChecksEnded => "Derivation checks ended",
36	            Phase::Closed => "Theory closed",
37	        }
38	    }
39	}
40	
41	/// The five progress phases a closed theory reports.
42	pub const CLOSED_PHASES: [Phase; 5] = [
43	    Phase::Loaded,
44	    Phase::Translated,
45	    Phase::DerivationChecksStarted,
46	    Phase::DerivationChecksEnded,
47	    Phase::Closed,
48	];
49	
50	/// One progress line: `[Theory <name>] <phase>\n` (stderr).
51	pub fn progress_line(theory: &str, phase: Phase) -> String {
52	    format!("[Theory {}] {}\n", theory, phase.text())
53	}
54	
55	fn progress_block(theory: &str, phases: &[Phase]) -> String {
56	    phases.iter().map(|p| progress_line(theory, *p)).collect()
57	}
58	
59	/// Whether a lemma quantifies over all traces or asserts an existing trace.
60	#[derive(Debug, Clone, Copy)]
61	pub enum TraceKind {
62	    AllTraces,
63	    ExistsTrace,
64	}
65	
66	impl TraceKind {
67	    fn text(self) -> &'static str {
68	        match self {
69	            TraceKind::AllTraces => "all-traces",
70	            TraceKind::ExistsTrace => "exists-trace",
71	        }
72	    }
73	}
74	
75	/// Per-lemma verdict.
76	#[derive(Debug, Clone, Copy)]
77	pub enum LemmaResult {
78	    Verified,
79	    Falsified,
80	    AnalysisIncomplete,
81	}
82	
83	impl LemmaResult {
84	    fn text(self) -> &'static str {
85	        match self {
86	            LemmaResult::Verified => "verified",
87	            LemmaResult::Falsified => "falsified",
88	            LemmaResult::AnalysisIncomplete => "analysis incomplete",
89	        }
90	    }
91	}
92	
93	/// One line of a theory's summary body.
94	#[derive(Debug, Clone)]
95	pub enum SummaryEntry {
96	    Lemma { name: String, kind: TraceKind, result: LemmaResult, steps: u64 },
97	    /// `WARNING: <count> wellformedness check failed!` (note the singular "check").
98	    Warning { count: u64 },
99	}
100	
101	impl SummaryEntry {
102	    fn text(&self) -> String {
103	        match self {
104	            SummaryEntry::Lemma { name, kind, result, steps } => {
105	                format!("{} ({}): {} ({} steps)", name, kind.text(), result.text(), steps)
106	            }
107	            SummaryEntry::Warning { count } => {
108	                format!("WARNING: {} wellformedness check failed!", count)
109	            }
110	        }
111	    }
112	}
113	
114	/// One theory's contribution to the "summary of summaries" block.
115	#[derive(Debug, Clone)]
116	pub struct Summary {
117	    /// The `analyzed:` path, echoed exactly as given on the command line.
118	    pub analyzed: String,
119	    /// The `output:` path, present only when the theory was written to a file
120	    /// (`-o`/`-O`).
121	    pub output: Option<String>,
122	    /// Rendered as seconds with two decimals (e.g. `0.39s`).
123	    pub processing_time: f64,
124	    pub entries: Vec<SummaryEntry>,
125	}
126	
127	impl Summary {
128	    /// The theory's block: the `analyzed:` header, a blank line, the aligned
129	    /// key/value rows (`output:` when present, then `processing time:`), the
130	    /// two-space separator line, then one line per entry.
131	    fn render_block(&self) -> String {
132	        let mut b = String::new();
133	        b.push_str(&format!("analyzed: {}\n", self.analyzed));
134	        b.push('\n');
135	
136	        // Aligned key/value rows: labels right-padded to the widest label, then a
137	        // single space, so every value starts at the same column.
138	        let mut rows: Vec<(&str, String)> = Vec::new();
139	        if let Some(o) = &self.output {
140	            rows.push(("output:", o.clone()));
141	        }
142	        rows.push(("processing time:", format!("{:.2}s", self.processing_time)));
143	        let width = rows.iter().map(|(label, _)| label.len()).max().unwrap_or(0);
144	        for (label, value) in &rows {
145	            b.push_str("  ");
146	            b.push_str(label);
147	            for _ in 0..(width - label.len()) {
148	                b.push(' ');
149	            }
150	            b.push(' ');
151	            b.push_str(value);
152	            b.push('\n');
153	        }
154	
155	        b.push_str("  \n"); // literal two-space separator line
156	        for e in &self.entries {
157	            b.push_str(&format!("  {}\n", e.text()));
158	        }
159	        b
160	    }
161	}
162	
163	/// The full "summary of summaries" section as it appears on stdout: a leading
164	/// blank line (the payload/summary separator, always present), the top `=` rule,
165	/// the header, each theory block preceded by a blank line, a trailing blank line,
166	/// and the bottom rule.
167	pub fn render_summary(summaries: &[Summary]) -> String {
168	    let rule = "=".repeat(RULE_WIDTH);
169	    let mut out = String::new();
170	    out.push('\n');
171	    out.push_str(&rule);
172	    out.push('\n');
173	    out.push_str("summary of summaries:\n");
174	    for s in summaries {
175	        out.push('\n');
176	        out.push_str(&s.render_block());
177	    }
178	    out.push('\n');
179	    out.push_str(&rule);
180	    out.push('\n');
181	    out
182	}
183	
184	/// A theory processed by a closed batch run.
185	#[derive(Debug, Clone)]
186	pub struct BatchTheory {
187	    /// Name used in the `[Theory <name>]` progress markers (stderr).
188	    pub name: String,
189	    /// The printed theory payload (stdout), or `None` when it was written to an
190	    /// output file instead.
191	    pub payload: Option<String>,
192	    /// Further progress lines the engine emitted for this theory after the five
193	    /// closed phases (stderr), verbatim and newline-terminated. Empty for a plain
194	    /// analyze run; under `--prove` it carries the `[Saturating Sources] …` lines.
195	    pub extra_progress: String,
196	    /// This theory's summary contribution (stdout).
197	    pub summary: Summary,
198	}
199	
200	/// A closed batch run over one or more theories.
201	///
202	/// stderr: the maude preamble, then per theory the five progress markers followed
203	/// by any extra engine progress. stdout: the printed payloads (in order), then one
204	/// combined summary block.
205	pub fn frame_batch(maude: &MaudeInfo, theories: &[BatchTheory]) -> Streams {
206	    let mut s = Streams::default();
207	    s.err.push_str(&maude_preamble(maude));
208	    for t in theories {
209	        s.err.push_str(&progress_block(&t.name, &CLOSED_PHASES));
210	        s.err.push_str(&t.extra_progress);
211	    }
212	    for t in theories {
213	        if let Some(p) = &t.payload {
214	            s.out.push_str(p);
215	        }
216	    }
217	    let summaries: Vec<Summary> = theories.iter().map(|t| t.summary.clone()).collect();
218	    s.out.push_str(&render_summary(&summaries));
219	    s
220	}
221	
222	/// A theory under `--parse-only`: its name (for the single progress marker) and
223	/// its opaque payload.
224	#[derive(Debug, Clone)]
225	pub struct LoadedTheory {
226	    pub name: String,
227	    pub payload: String,
228	}
229	
230	/// A `--parse-only` run: stderr carries one `Theory loaded` marker per theory (no
231	/// preamble); stdout carries the concatenated payloads (no summary block).
232	pub fn frame_parse_only(theories: &[LoadedTheory]) -> Streams {
233	    let mut s = Streams::default();
234	    for t in theories {
235	        s.err.push_str(&progress_line(&t.name, Phase::Loaded));
236	        s.out.push_str(&t.payload);
237	    }
238	    s
239	}
240	
241	/// A `variants` run: stdout carries the variant payload; stderr carries only the
242	/// maude preamble (no progress markers, no summary).
243	pub fn frame_variants(maude: &MaudeInfo, payload: &str) -> Streams {
244	    Streams { out: payload.to_string(), err: maude_preamble(maude) }
245	}
246

1	//! Workspace adapter routing this crate's `--help` / `--version` rendering
2	//! through the vendored clean-room console text modules (`super::help`,
3	//! `super::version`, `super::modes`). This file is pure type conversion and
4	//! data plumbing: it maps the ported [`super::Subcommand`] to the clean
5	//! [`Mode`] and fills the clean [`VersionInfo`] slots from this binary's own
6	//! build metadata (`super::VERSION` / `GIT_REV` / `GIT_BRANCH` /
7	//! `BUILD_TIMESTAMP`) and the detected Maude version. No render logic lives
8	//! here — the byte-exact HS text comes entirely from the clean modules.
9	
10	use super::help::render_help;
11	use super::modes::Mode;
12	use super::version::{render_version, MaudeInfo, VersionInfo};
13	use super::Subcommand;
14	
15	/// Map the ported subcommand to the clean text-surface mode.
16	fn mode_of(sub: &Subcommand) -> Mode {
17	    match sub {
18	        Subcommand::Batch => Mode::Batch,
19	        Subcommand::Interactive => Mode::Interactive,
20	        Subcommand::Variants => Mode::Variants,
21	        Subcommand::Test => Mode::Test,
22	    }
23	}
24	
25	/// The byte-exact HS help page for the active subcommand.
26	pub fn help_text(sub: &Subcommand) -> &'static str {
27	    render_help(mode_of(sub))
28	}
29	
30	/// The default (batch) help page — for callers with no subcommand in scope
31	/// (parse-error fallback, batch "no input files" envelope).
32	pub fn help_text_default() -> &'static str {
33	    render_help(Mode::Batch)
34	}
35	
36	/// The full `--version` banner, byte-exact against the HS `--version` capture
37	/// (the interleaved 2>&1 form the clean template models), with this binary's
38	/// build metadata in the slots. Rendered as a single string printed to stdout;
39	/// unlike the removed ported path it does not split the maude self-check lines
40	/// onto stderr (the clean template does not model stream separation).
41	pub fn version_stdout() -> String {
42	    let maude_version =
43	        super::detect_maude_version_pub().unwrap_or_else(|| "unknown version".to_string());
44	    let info = VersionInfo {
45	        maude: MaudeInfo { path: "maude".to_string(), version: maude_version },
46	        tamarin_version: super::VERSION.to_string(),
47	        copyright_years: "2010-2023".to_string(),
48	        git_description: format!("{}, branch: {}", super::GIT_REV, super::GIT_BRANCH),
49	        compiled_at: super::BUILD_TIMESTAMP.to_string(),
50	    };
51	    render_version(&info)
52	}
53	
54	#[cfg(test)]
55	mod tests {
56	    use super::*;
57	
58	    #[test]
59	    fn help_is_the_hs_global_page() {
60	        // Byte-exact against the vendored HS capture, and mode-selective.
61	        assert_eq!(help_text(&Subcommand::Batch), include_str!("fixtures/help_global.txt"));
62	        assert_eq!(help_text(&Subcommand::Interactive), include_str!("fixtures/help_interactive.txt"));
63	        assert_eq!(help_text(&Subcommand::Variants), include_str!("fixtures/help_variants.txt"));
64	        assert_eq!(help_text(&Subcommand::Test), include_str!("fixtures/help_test.txt"));
65	    }
66	
67	    #[test]
68	    fn version_uses_clean_template_and_fills_slots() {
69	        let out = version_stdout();
70	        // Static template text (byte-exact HS) is present and interleaved.
71	        assert!(out.starts_with("maude tool: 'maude'\n checking version: tamarin-prover "));
72	        assert!(out.contains("This program comes with ABSOLUTELY NO WARRANTY."));
73	        assert!(out.contains("\n checking installation: OK.\nGenerated from:\n"));
74	        // Build-metadata slots are filled from this binary.
75	        assert!(out.contains(&format!("Tamarin version {}\n", super::super::VERSION)));
76	        assert!(out.contains(&format!("branch: {}\n", super::super::GIT_BRANCH)));
77	        assert!(out.ends_with("\n"));
78	    }
79	}
