328	/// Parse a raw argv-style slice (program name NOT included).
329	pub fn parse_args(raw: &[String]) -> Result<Args, CliError> {
330	    let mut args = Args::default();
331	
332	    // Subcommand detection: if the first non-option token is a known
333	    // subcommand name, route to it. Otherwise stay in batch mode.
334	    let mut i = 0;
335	    if let Some(first) = raw.first() {
336	        match first.as_str() {
337	            "interactive" => {
338	                args.subcommand = Subcommand::Interactive;
339	                i = 1;
340	            }
341	            "variants" => {
342	                args.subcommand = Subcommand::Variants;
343	                i = 1;
344	            }
345	            "test" | "test-prover" => {
346	                args.subcommand = Subcommand::Test;
347	                i = 1;
348	            }
349	            _ => {}
350	        }
351	    }
352	
353	    // A few short flags take a separate-token value (`-b N`, `-s N`,
354	    // `-o FILE`, etc.). We dispatch on full-name so all such cases
355	    // are explicit.
356	
357	    let mut positional: Vec<String> = Vec::new();
358	    while i < raw.len() {
359	        let a = &raw[i];
360	        if a == "--" {
361	            // Everything after is positional.
362	            for x in &raw[(i + 1)..] {
363	                positional.push(x.clone());
364	            }
365	            break;
366	        }
367	
368	        // Long flag.
369	        if let Some(rest) = a.strip_prefix("--") {
370	            let (key, val_inline) = split_eq(rest);
371	            match key {
372	                "help" => args.show_help = true,
373	                "version" => args.show_version = true,
374	                "prove" => {
375	                    args.prove_mode = true;
376	                    if let Some(v) = val_inline {
377	                        args.lemma_names.push(v.to_string());
378	                    } else {
379	                        // bare --prove → match-everything sentinel
380	                        args.lemma_names.push(String::new());
381	                    }
382	                }
383	                "lemma" => {
384	                    if let Some(v) = val_inline {
385	                        args.lemma_names.push(v.to_string());
386	                    } else {
387	                        args.lemma_names.push(String::new());
388	                    }
389	                }
390	                // flagOpt "dfs" — bare flag records the default "dfs", which
391	                // equals the Rust default; absent leaves None (same behaviour).
392	                "stop-on-trace" => {
393	                    let v = flag_opt(val_inline, "dfs");
394	                    args.stop_on_trace = Some(StopOnTrace::parse(&v).map_err(CliError::Msg)?);
395	                }
396	                // flagOpt "5" (TheoryLoader.hs:105-110).  Load-bearing: HS
397	                // `proofBound = parseIntArg (findArg "bound") Nothing Just`, so
398	                // bare `--bound` records the default "5" => Some(5) (bounded
399	                // search) while an absent `--bound` stays None (unbounded).
400	                "bound" => {
401	                    let v = flag_opt(val_inline, "5");
402	                    args.bound = Some(parse_int(&v, "bound")?);
403	                }
404	                "heuristic" => {
405	                    // flagOpt default = head of defaultRankings False; that
406	                    // default rebuilds the Rust default downstream, so a bare
407	                    // flag is behaviourally equal to absent — leave None.
408	                    // Routed: when set, this OVERRIDES the per-lemma / theory
409	                    // heuristic for every lemma (HS `selectHeuristic`:
410	                    // `apDefaultHeuristic <|> pcHeuristic`, Proof.hs:707).
411	                    if let Some(v) = val_inline {
412	                        args.heuristic = Some(v.to_string());
413	                    }
414	                }
415	                "partial-evaluation" => {
416	                    let v = flag_opt(val_inline, "summary");
417	                    args.partial_evaluation =
418	                        Some(PartialEval::parse(&v).map_err(CliError::Msg)?);
419	                }
420	                "defines" => {
421	                    // flagOpt "" — bare `-D`/`--defines` records the empty
422	                    // string default (a no-op #define), matching HS.
423	                    args.defines.push(flag_opt(val_inline, ""));
424	                }
425	                "diff" => args.diff = true,
426	                "quit-on-warning" => args.quit_on_warning = true,
427	                "auto-sources" => args.auto_sources = true,
428	                "oraclename" => {
429	                    // Routed: sets the oracle relPath on every oracle ranking
430	                    // in the `--heuristic` chain (HS `mapOracleRanking
431	                    // (maybeSetOracleRelPath oraclename)`, TheoryLoader.hs:305).
432	                    // `Just "" -> Nothing` is handled at resolution time.
433	                    args.oracle_name = Some(flag_opt(val_inline, ""));
434	                }
435	                // Routed: `--oracle-only` sets quitOnEmpty on every oracle /
436	                // tactic ranking in the selected heuristic (HS `setQuitOnEmpty`,
437	                // Proof.hs:712-716).
438	                "oracle-only" => args.oracle_only = true,
439	                "quiet" => args.quiet = true,
440	                "verbose" => args.verbose = true,
441	                "open-chains" => {
442	                    let v = flag_opt(val_inline, "10");
443	                    args.open_chains = Some(parse_int(&v, "open-chains")?);
444	                }
445	                "saturation" => {
446	                    let v = flag_opt(val_inline, "5");
447	                    args.saturation = Some(parse_int(&v, "saturation")?);
448	                }
449	                "derivcheck-timeout" => {
450	                    let v = flag_opt(val_inline, "5");
