452	                }
453	                "no-reuse" => args.no_reuse = true,
454	                "no-restrictions" => args.no_restrictions = true,
455	                "replication-bound" => {
456	                    let v = flag_opt(val_inline, "3");
457	                    args.replication_bound = Some(parse_int(&v, "replication-bound")?);
458	                }
459	                "no-compress" => args.no_compress = true,
460	                "parse-only" => args.parse_only = true,
461	                "precompute-only" => args.precompute_only = true,
462	                "processors" => {
463	                    args.processors =
464	                        Some(parse_positive_usize(&mut i, raw, val_inline, "processors")?);
465	                }
466	                "maude-processes" => {
467	                    args.maude_processes =
468	                        Some(parse_positive_usize(&mut i, raw, val_inline, "maude-processes")?);
469	                }
470	                // Output flags.  output / Output / output-module are flagOpt
471	                // (Batch.hs:76-78): only `=VALUE` or a bare flag (records the
472	                // default ""/""/"spthy"); they never consume the next token.
473	                "output" => {
474	                    args.output_file = Some(flag_opt(val_inline, ""));
475	                }
476	                // The long form in Haskell is `--Output` (capital O) for the
477	                // directory variant (Batch.hs:77 registers only `Output`/`O`);
478	                // there is no `--output-dir` alias, so it falls through to the
479	                // unknown-flag arm, exactly as HS does.
480	                "Output" => {
481	                    args.output_dir = Some(flag_opt(val_inline, ""));
482	                }
483	                "output-module" => {
484	                    args.output_module = Some(flag_opt(val_inline, "spthy"));
485	                }
486	                // output-json / output-dot are flagReq (Batch.hs:79-80): they
487	                // REQUIRE a value and DO consume a separate next token.
488	                "output-json" | "oj" => {
489	                    let v = take_val(&mut i, raw, val_inline, "output-json")?;
490	                    args.trace_json = Some(v);
491	                }
492	                "output-dot" | "od" => {
493	                    let v = take_val(&mut i, raw, val_inline, "output-dot")?;
494	                    args.trace_dot = Some(v);
495	                }
496	                // toolFlags are flagOpt (Environment.hs:31-33): defaults
497	                // maude/dot/json; bare flag records the default, no token.
498	                "with-maude" => {
499	                    args.maude_path = Some(flag_opt(val_inline, "maude"));
500	                }
501	                "with-dot" => {
502	                    args.dot_path = Some(flag_opt(val_inline, "dot"));
503	                }
504	                "with-json" => {
505	                    args.json_path = Some(flag_opt(val_inline, "json"));
506	                }
507	                // Interactive-mode flags are flagOpt (Interactive.hs:53-56),
508	                // so they never consume a separate token — only `=VALUE`.  A
509	                // bare flag records the empty-string default; HS then reads
510	                // port leniently (Interactive.hs:134-139, falls back to
511	                // defaultPort) and interface defaults to 127.0.0.1
512	                // (Interactive.hs:143), so an empty value behaves like absent.
513	                "port" => {
514	                    if let Some(v) = val_inline {
515	                        if !v.is_empty() {
516	                            args.port = Some(parse_int(v, "port")?);
517	                        }
518	                    }
519	                }
520	                "interface" => {
521	                    args.interface = Some(flag_opt(val_inline, ""));
522	                }
523	                "image-format" => {
524	                    if let Some(v) = val_inline {
525	                        if !v.is_empty() {
526	                            args.image_format =
527	                                Some(ImageFormat::parse(v).map_err(CliError::Msg)?);
528	                        }
529	                    }
530	                }
531	                "debug" => args.debug = true,
532	                "no-logging" => args.no_logging = true,
533	                "data-dir" => {
534	                    let v = take_val(&mut i, raw, val_inline, "data-dir")?;
535	                    args.data_dir = Some(v);
536	                }
537	                other => {
538	                    return Err(CliError::Msg(format!("unknown flag: --{}", other)));
539	                }
540	            }
541	            i += 1;
542	            continue;
543	        }
544	
545	        // Short flag(s). cmdargs in Haskell uses single-letter -X aliases.
546	        if let Some(rest) = a.strip_prefix('-') {
547	            if rest.is_empty() {
548	                // bare `-` — treat as positional (stdin convention)
549	                positional.push(a.clone());
550	                i += 1;
551	                continue;
552	            }
553	            // GNU-style clustering of boolean short flags, mirroring
554	            // System.Console.CmdArgs.Explicit (`-vh` sets both verbose
555	            // and help; HS `verbose`/`help`/`version` are all
556	            // no-argument `flagNone`/`flagHelpSimple`/`flagVersion`).
557	            // We walk the cluster char-by-char: a boolean short consumes
558	            // exactly one char and we continue with the rest; the first
559	            // value-taking short consumes the remainder of the token as
560	            // its inline value (e.g. `-b12`, `-vb12`) and ends the cluster.
561	            // All the value-taking shorts here are cmdargs `flagOpt`, so they
562	            // do NOT consume the next (space-separated) token; a bare short
563	            // (`-b`) records the flag's default.  Verified against the HS
564	            // binary: `-b 5 t.spthy` keeps `5` positional (`5: openFile: does
565	            // not exist`); `-b5` is inline; bare `-b` uses default 5.
566	            for (idx, key) in rest.char_indices() {
567	                // Bytes after this char in the token form a potential
568	                // inline value for a value-taking flag.  Strip a single
569	                // leading `=` to keep `-b=12` working.
570	                let after = &rest[idx + key.len_utf8()..];
571	                let inline_raw = after.strip_prefix('=').unwrap_or(after);
572	                let inline: Option<&str> =
573	                    if inline_raw.is_empty() { None } else { Some(inline_raw) };
574	                match key {
575	                    'h' | '?' => {
576	                        args.show_help = true;
577	                        continue;
578	                    }
579	                    'V' => {
580	                        args.show_version = true;
581	                        continue;
582	                    }
583	                    'v' => {
584	                        args.verbose = true;
585	                        continue;
586	                    }
587	                    'b' => {
588	                        let v = flag_opt(inline, "5");
589	                        args.bound = Some(parse_int(&v, "bound")?);
590	                    }
591	                    's' => {
592	                        let v = flag_opt(inline, "5");
593	                        args.saturation = Some(parse_int(&v, "saturation")?);
594	                    }
595	                    'c' => {
596	                        let v = flag_opt(inline, "10");
597	                        args.open_chains = Some(parse_int(&v, "open-chains")?);
598	                    }
599	                    'd' => {
600	                        let v = flag_opt(inline, "5");
601	                        args.derivcheck_timeout = Some(parse_int(&v, "derivcheck-timeout")?);
602	                    }
603	                    'D' => {
604	                        args.defines.push(flag_opt(inline, ""));
605	                    }
606	                    'o' => {
607	                        args.output_file = Some(flag_opt(inline, ""));
608	                    }
609	                    'O' => {
610	                        args.output_dir = Some(flag_opt(inline, ""));
611	                    }
612	                    'm' => {
613	                        args.output_module = Some(flag_opt(inline, "spthy"));
614	                    }
615	                    'p' => {
616	                        if let Some(v) = inline {
617	                            args.port = Some(parse_int(v, "port")?);
618	                        }
619	                    }
620	                    'i' => {
621	                        args.interface = Some(flag_opt(inline, ""));
622	                    }
623	                    other => {
624	                        return Err(CliError::Msg(format!("unknown short flag: -{}", other)));
625	                    }
626	                }
627	                // A value-taking flag consumed the remainder of the
628	                // token (and possibly the next token); stop scanning
629	                // this cluster.
630	                break;
631	            }
632	            i += 1;
633	            continue;
634	        }
635	
636	        // Positional.
637	        positional.push(a.clone());
638	        i += 1;
639	    }
640	    args.in_files = positional;
641	
642	    Ok(args)
643	}
