646	    /// Resolve `--processors` (or its default).  Default = full
647	    /// machine parallelism (`available_parallelism()`); Maude IPC mutex

645	impl Args {
646	    /// Resolve `--processors` (or its default).  Default = full
647	    /// machine parallelism (`available_parallelism()`); Maude IPC mutex
648	    /// contention is mediated by the `MaudePool` (`--maude-processes`),
649	    /// so every core can be used.
650	    pub fn effective_processors(&self) -> usize {
651	        match self.processors {
652	            Some(n) => n.max(1),
653	            None => std::thread::available_parallelism()
654	                .map(|p| p.get())
655	                .unwrap_or(1),
656	        }
657	    }
658	
659	    /// Resolve `--maude-processes` (or its default).
660	    ///
661	    /// Default = `max(1, effective_processors())` — a 1:1
662	    /// workers:maudes ratio.  Lemma-level parallelism (B1) plus the
663	    /// within-lemma fan-out both draw Maude handles from this pool
664	    /// concurrently, so a half-size pool would be exhausted, forcing the
665	    /// fan-out to fall back to the single shared subprocess (serialised
666	    /// IPC).  At 1:1 the
667	    /// Maude-bound theories keep more queries in flight (gcm ~-8%,
668	    /// Yubikey ~-12% @16c; output-identical — Maude is stateless so pool
669	    /// size never affects results).  Costs ~30-100 MB per extra
670	    /// subprocess on real protocols; tight-RAM users can dial it back
671	    /// with `--maude-processes=N`.  Going ABOVE `procs` over-subscribes
672	    /// and regresses (measured), so do not raise the default further.
673	    ///
674	    /// When `--processors=1`, force pool size 1 (no parallelism to
675	    /// exploit; saves spawn cost).
676	    pub fn effective_maude_processes(&self) -> usize {
677	        let procs = self.effective_processors();
678	        if procs == 1 {
679	            return 1;
680	        }
681	        match self.maude_processes {
682	            Some(n) => n.max(1),
683	            None => procs.max(1),
684	        }
685	    }
686	}
