707	fn take_val(
708	    i: &mut usize,
709	    raw: &[String],
710	    inline: Option<&str>,
711	    name: &str,
712	) -> Result<String, CliError> {
713	    if let Some(v) = inline {
714	        return Ok(v.to_string());
715	    }
716	    let next = raw.get(*i + 1).cloned().ok_or_else(|| {
717	        CliError::Msg(format!("flag --{} requires a value", name))
718	    })?;
719	    if next.starts_with('-') {
720	        return Err(CliError::Msg(format!(
721	            "flag --{} requires a value (got {:?})",
722	            name, next
723	        )));
724	    }
725	    *i += 1;
726	    Ok(next)
727	}
