735	/// Take a flag's value, parse it as a `usize`, and reject `0` with a
736	/// `--<name> must be >= 1` error.  Shared by the `--processors` and
737	/// `--maude-processes` arms, which are otherwise identical.
738	fn parse_positive_usize(
739	    i: &mut usize,
740	    raw: &[String],
741	    inline: Option<&str>,
742	    name: &str,
743	) -> Result<usize, CliError> {
744	    let v = take_val(i, raw, inline, name)?;
745	    let n: usize = parse_int(&v, name)?;
746	    if n == 0 {
747	        return Err(CliError::Msg(format!("--{} must be >= 1", name)));
748	    }
749	    Ok(n)
750	}
