752	/// Does the lemma name match the user's `--prove`/`--lemma` filter?
753	///
754	/// Mirrors HS `lemmaSelector` (TheoryLoader.hs:378-389): the empty
755	/// filter `[]`, the single-empty filter `[""]`, and the double-empty
756	/// filter `["",""]` all mean "all lemmas".  Otherwise we run
757	/// `any lemmaMatches filter` where a pattern ending in `*` matches by
758	/// prefix (with the `*` dropped) and any other pattern (including a
759	/// bare `""`) matches only by exact name.  Note this is NOT "drop all
760	/// empties": three or more bare entries (e.g. `["","",""]`) fall
761	/// through to the `any` arm and match nothing, exactly like HS.
762	pub fn lemma_matches(filter: &[String], lemma_name: &str) -> bool {
763	    match filter.len() {
764	        0 => return true,
765	        1 if filter[0].is_empty() => return true,
766	        2 if filter[0].is_empty() && filter[1].is_empty() => return true,
767	        _ => {}
768	    }
769	    filter.iter().any(|pat| {
770	        if let Some(prefix) = pat.strip_suffix('*') {
771	            lemma_name.starts_with(prefix)
772	        } else {
773	            pat == lemma_name
774	        }
775	    })
776	}
