1516	/// Install rayon's global worker pool to the size requested via
1517	/// `--processors=N` (or a sensible default).
1518	///
1519	/// HS-equivalent: GHC's `+RTS -N RTS_FLAG` sets the worker capacity for
1520	/// the `par*`/`Strategies` sites HS uses.  We mirror that surface via a
1521	/// CLI flag.  Idempotent across files in a batch — `build_global`
1522	/// silently errors on the second call, which is what we want.
1523	///
1524	/// Default: `available_parallelism()` (full machine).  `MaudePool`
1525	/// (`--maude-processes=M`) removes the Maude IPC mutex contention that
1526	/// would otherwise serialise every worker on a single subprocess, so
1527	/// users can productively scale to every core.  Memory budget is
1528	/// mediated by `--maude-processes`, which defaults to `processors` (1:1).
1529	fn init_rayon_pool(args: &Args) {
1530	    let n = args.effective_processors();
1531	    // `build_global` is idempotent-error: the SECOND call returns Err
1532	    // even if N matches.  We swallow the error: the first invocation
1533	    // wins (which is the desired behaviour — RS runs `run_batch` once
1534	    // per process, and tests install their own pool).
1535	    let _ = rayon::ThreadPoolBuilder::new()
1536	        .num_threads(n)
1537	        .thread_name(|i| format!("tamarin-rayon-{}", i))
1538	        .build_global();
1539	}
