1603	fn print_overall_summary(file_results: &[FileResult], prove_mode: bool) {
1604	    // Mirrors HS `summary of summaries:` block (`Main.Mode.Batch`).
1605	    let line = "=".repeat(78);
1606	    println!();
1607	    println!("{}", line);
1608	    println!("summary of summaries:");
1609	    println!();
1610	    for fr in file_results {
1611	        println!("analyzed: {}", fr.in_file);
1612	        // HS `ppRep` (Batch.hs:146-148) has TWO `Pretty.text ""` between
1613	        // `analyzed:` and the nested `output:`/`processing time:` block, but
1614	        // HughesPJ collapses adjacent empty lines under `vcat`, so the rendered
1615	        // output is a SINGLE blank line here.  Verified against the v1.13.0
1616	        // binary: `tamarin-prover --prove` emits exactly one blank line between
1617	        // `analyzed:` and `output:`/`processing time:`, so one `println!()` is
1618	        // byte-faithful.
1619	        println!();
1620	        if let Some(out) = &fr.out_file {
1621	            // HS aligns `output:` and `processing time:` columns
1622	            // (`ppRep` in Main.Mode.Batch, src/Main/Mode/Batch.hs:144).
1623	            println!("  output:          {}", out);
1624	        }
1625	        println!("  processing time: {:.2}s", fr.elapsed_ms as f64 / 1000.0);
1626	        println!("  ");
1627	        if fr.wf_count > 0 {
1628	            println!("  WARNING: {} wellformedness check failed!", fr.wf_count);
1629	            // HS Batch.hs:246 emits this second line only in prove mode:
1630	            //   [ Pretty.text "         The analysis results might be wrong!"
1631	            //   | thyLoadOptions.proveMode ]
1632	            if prove_mode {
1633	                println!("           The analysis results might be wrong!");
1634	            }
1635	            // HS `summary = ppWf report $--$ prettyClosedSummary` (Batch.hs:228-229):
1636	            // `$--$` (above with a blank-line gap) inserts the blank ONLY when
1637	            // both operands are non-empty.  Under the enclosing `nest 2` a
1638	            // blank `Pretty.text ""` renders as `"  "`.  So this separator
1639	            // appears between the warning block and the per-lemma summary

1640	            // lines ONLY when there are summary lines to follow; emitting it
1641	            // unconditionally would add a spurious trailing `"  "` line.
1642	            if !fr.results.is_empty() {
1643	                println!("  ");
1644	            }
1645	        }
1646	        for r in &fr.results {
1647	            println!("  {}", format_lemma_summary_line(r));
1648	        }
1649	        println!();
1650	    }
1651	    println!("{}", line);
1652	}
