60	    let args = args_from(&[
61	        "--prove=chain",
62	        &output_arg,
63	        "--quiet",
64	        in_path.to_str().unwrap(),
65	    ]);
66	    let code = run(&args).expect("run");
67	    assert_eq!(code, 0, "expected exit code 0, got {}", code);
68	
69	    // The proven theory is written to the output file with the chain
70	    // lemma's proof inline.  HS-faithful: the `summary of summaries`
71	    // verdict block (verified/analyzed/...) goes to STDOUT, not the `-o`
72	    // file.  `chain` is an exists-trace lemma satisfied by the example, so
73	    // its proof ends in `SOLVED // trace found` + `qed` (verified
74	    // byte-identical to the Haskell binary's output file for this fixture).
75	    let body = std::fs::read_to_string(&out_path).expect("output written");
76	    assert!(
77	        body.contains("theory SingleRecv"),
78	        "output should contain original theory; got:\n{}",
79	        body
80	    );
81	    assert!(
82	        body.contains("lemma chain")
83	            && body.contains("SOLVED // trace found")
84	            && body.contains("qed"),
85	        "output file should contain the completed chain proof; got:\n{}",
86	        body
87	    );
88	}
